      if (mode === 'server') {
        return {
          deviceName: 'Gateway-PROFINET-Device',
          vendorId: 0x0001,
          deviceId: 0x0001,
          ip: '192.168.1.100',
          netmask: '255.255.255.0',
          gateway: '192.168.1.1',
          slots: [{
