// PROFINET Configuration Props
interface ProfinetConfigProps {
  protocol: ProtocolConfig;
  onUpdate: (updates: Record<string, any>) => void;
  onProtocolUpdate: (updates: Partial<ProtocolConfig>) => void;
}

const ProfinetConfig: React.FC<ProfinetConfigProps> = ({ protocol, onUpdate, onProtocolUpdate }) => {
  const settings = protocol.settings;

  return (
    <div>
      {/* Mode-specific configuration */}
      {protocol.mode === 'client' ? (
        <ProfinetClientConfig settings={settings} onUpdate={onUpdate} />
      ) : (
        <ProfinetServerConfig settings={settings} onUpdate={onUpdate} />
      )}
    </div>
  );
};

