// PROFINET Slot/Module Configuration for server mode
const ProfinetSlotConfiguration: React.FC<{ settings: any; onUpdate: (updates: Record<string, any>) => void }> = ({ settings, onUpdate }) => {
  const slots = settings.slots || [];

  return (
    <div style={{
      backgroundColor: '#ffffff',
      border: '1px solid #dee2e6',
      borderRadius: '6px',
      padding: '16px'
    }}>
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '12px' }}>
        <h4 style={{ margin: 0, fontSize: '14px', fontWeight: '600', color: '#495057' }}>
          Module/Slot Configuration ({slots.length})
        </h4>
        <button
          onClick={() => {
            const newSlot = {
              slotNumber: slots.length,
              moduleId: 1,
              subslots: [
                { subslotNumber: 1, ioData: { inputs: 32, outputs: 32 } }
              ]
            };
            onUpdate({
              slots: [...slots, newSlot]
            });
          }}
          style={{
            padding: '4px 8px',
            fontSize: '11px',
            backgroundColor: '#28a745',
            color: 'white',
            border: 'none',
            borderRadius: '4px',
            cursor: 'pointer'
          }}
        >
          + Add Slot
        </button>
      </div>

      {slots.map((slot: any, index: number) => (
        <div
          key={index}
          style={{
            border: '1px solid #e9ecef',
            borderRadius: '4px',
            padding: '12px',
            marginBottom: '8px',
            backgroundColor: '#f8f9fa'
          }}
        >
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr auto', gap: '8px', alignItems: 'center', marginBottom: '8px' }}>
            <div>
              <label style={{ display: 'block', fontSize: '10px', fontWeight: '500', color: '#6c757d', marginBottom: '2px' }}>
                Slot Number
              </label>
              <input
                type="number"
                value={slot.slotNumber}
