                  const updatedSlots = [...slots];
                  updatedSlots[index] = { ...slot, slotNumber: parseInt(e.target.value) || 0 };
                  onUpdate({ slots: updatedSlots });
                }}
                style={{
                  width: '100%',
                  padding: '4px 6px',
                  border: '1px solid #ced4da',
                  borderRadius: '3px',
                  fontSize: '11px'
                }}
              />
            </div>
            
            <div>
              <label style={{ display: 'block', fontSize: '10px', fontWeight: '500', color: '#6c757d', marginBottom: '2px' }}>
                Module ID
              </label>
              <input
                type="number"
                value={slot.moduleId}
                onChange={(e) => {
                  const updatedSlots = [...slots];
                  updatedSlots[index] = { ...slot, moduleId: parseInt(e.target.value) || 1 };
                  onUpdate({ slots: updatedSlots });
                }}
                style={{
                  width: '100%',
                  padding: '4px 6px',
                  border: '1px solid #ced4da',
                  borderRadius: '3px',
                  fontSize: '11px'
                }}
              />
            </div>
            
            <button
              onClick={() => {
                const updatedSlots = slots.filter((_: any, i: number) => i !== index);
                onUpdate({ slots: updatedSlots });
              }}
              style={{
                padding: '4px 6px',
                fontSize: '10px',
                backgroundColor: '#dc3545',
                color: 'white',
                border: 'none',
                borderRadius: '3px',
                cursor: 'pointer',
                marginTop: '12px'
              }}
            >
              ×
            </button>
          </div>

          {/* Subslots */}
          <div style={{ marginLeft: '16px' }}>
            <h6 style={{ fontSize: '11px', fontWeight: '600', color: '#495057', margin: '0 0 6px 0' }}>
              Subslots ({(slot.subslots || []).length})
