            {(slot.subslots || []).map((subslot: any, subIndex: number) => (
              <div key={subIndex} style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '6px', marginBottom: '6px', fontSize: '10px' }}>
                <div>
                  <label style={{ display: 'block', fontSize: '9px', color: '#6c757d' }}>Subslot</label>
                  <input
                    type="number"
                    value={subslot.subslotNumber}
                    onChange={(e) => {
                      const updatedSlots = [...slots];
                      const updatedSubslots = [...(slot.subslots || [])];
                      updatedSubslots[subIndex] = { ...subslot, subslotNumber: parseInt(e.target.value) || 1 };
                      updatedSlots[index] = { ...slot, subslots: updatedSubslots };
                      onUpdate({ slots: updatedSlots });
                    }}
                    style={{ width: '100%', padding: '2px 4px', border: '1px solid #ced4da', borderRadius: '2px', fontSize: '10px' }}
                  />
                </div>
                <div>
                  <label style={{ display: 'block', fontSize: '9px', color: '#6c757d' }}>Inputs</label>
                  <input
                    type="number"
                    value={subslot.ioData?.inputs || 32}
                    onChange={(e) => {
                      const updatedSlots = [...slots];
                      const updatedSubslots = [...(slot.subslots || [])];
                      updatedSubslots[subIndex] = { 
                        ...subslot, 
                        ioData: { ...subslot.ioData, inputs: parseInt(e.target.value) || 32 }
                      };
                      updatedSlots[index] = { ...slot, subslots: updatedSubslots };
                      onUpdate({ slots: updatedSlots });
                    }}
                    style={{ width: '100%', padding: '2px 4px', border: '1px solid #ced4da', borderRadius: '2px', fontSize: '10px' }}
                  />
                </div>
                <div>
                  <label style={{ display: 'block', fontSize: '9px', color: '#6c757d' }}>Outputs</label>
                  <input
                    type="number"
                    value={subslot.ioData?.outputs || 32}
                    onChange={(e) => {
                      const updatedSlots = [...slots];
                      const updatedSubslots = [...(slot.subslots || [])];
                      updatedSubslots[subIndex] = { 
                        ...subslot, 
                        ioData: { ...subslot.ioData, outputs: parseInt(e.target.value) || 32 }
                      };
                      updatedSlots[index] = { ...slot, subslots: updatedSubslots };
                      onUpdate({ slots: updatedSlots });
                    }}
                    style={{ width: '100%', padding: '2px 4px', border: '1px solid #ced4da', borderRadius: '2px', fontSize: '10px' }}
                  />
                </div>
              </div>
            ))}
          </div>
        </div>
      ))}
    </div>
  );
};

// Helper Functions
function getDefaultProtocolSettings(type: ProtocolConfig['type'], mode: 'client' | 'server' = 'client'): Record<string, any> {
  switch (type) {
    case 'modbus-tcp':
      if (mode === 'server') {
        return {
          serverPort: 502,
          unitId: 1,
          maxConnections: 10,
          registerMap: {
            holdingRegisters: { start: 0, count: 1000, access: 'rw' },
            coils: { start: 0, count: 1000, access: 'rw' },
            inputRegisters: { start: 0, count: 1000, access: 'r' },
            discreteInputs: { start: 0, count: 1000, access: 'r' }
          }
        };
      } else {
        return {
          port: 502,
          timeout: 5000,
          retries: 3,
          devices: [],
          // Internal register map for gateway's own Modbus server
          registerMap: {
            holdingRegisters: { start: 0, count: 1000, access: 'rw' },
            coils: { start: 0, count: 1000, access: 'rw' },
            inputRegisters: { start: 0, count: 1000, access: 'r' },
            discreteInputs: { start: 0, count: 1000, access: 'r' }
          },
          internalServerPort: 5502 // Auto-started Modbus server for gateway's internal registers
        };
      }
    case 'opcua':
      return {
        endpoint: 'opc.tcp://localhost:4840',
        securityMode: 'None',
        securityPolicy: 'None'
      };
    case 'mqtt':
      return {
        broker: 'mqtt://localhost:1883',
        clientId: 'gateway-client',
        topics: []
      };
    case 'profinet':
      if (mode === 'server') {
        return {
          deviceName: 'Gateway-PROFINET-Device',
          vendorId: 0x0001,
          deviceId: 0x0001,
          ip: '192.168.1.100',
          netmask: '255.255.255.0',
          gateway: '192.168.1.1',
          slots: [
            {
              slotNumber: 0,
              moduleId: 0x0001,
              subslots: [
                { subslotNumber: 1, ioData: { inputs: 32, outputs: 32 } }
              ]
            }
          ]
        };
      } else {
        return {
          controllerIp: '192.168.1.10',
          timeout: 5000,
          devices: []
        };
      }
    default:
      return {};
  }
}

export default GatewayBuilder;
